import { ThemePreset, ColorTheme } from '../../types';

// ─── Palette ───────────────────────────────────────────────────────────────────

const PRESETS: Record<ColorTheme, ThemePreset> = {
  default: {
    label: 'Default',
    accent: '#2D5BE3',
    bg: '#F7F4EE',
    surface: '#FFFFFF',
    surface2: '#F0EDE6',
    dots: ['#2D5BE3', '#6366F1', '#A5B4FC'],
  },
  warm: {
    label: 'Warm sunset',
    accent: '#E85D75',
    bg: '#FFF8F5',
    surface: '#FFFFFF',
    surface2: '#FFF0EB',
    dots: ['#E85D75', '#F4A261', '#E9C46A'],
  },
  ocean: {
    label: 'Ocean breeze',
    accent: '#1A6DB5',
    bg: '#F0F7FF',
    surface: '#FFFFFF',
    surface2: '#E8F4FF',
    dots: ['#1A6DB5', '#00B4D8', '#90E0EF'],
  },
  forest: {
    label: 'Forest calm',
    accent: '#2D6A4F',
    bg: '#F2FAF5',
    surface: '#FFFFFF',
    surface2: '#E8F7EE',
    dots: ['#2D6A4F', '#52B788', '#D8F3DC'],
  },
  mono: {
    label: 'Monochrome',
    accent: '#2D2D2D',
    bg: '#F5F5F5',
    surface: '#FFFFFF',
    surface2: '#EBEBEB',
    dots: ['#2D2D2D', '#6B6B6B', '#C2C2C2'],
  },
};

export default PRESETS;
